export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (!arg.startsWith('--')) result._.push(arg)
    else if (arg.startsWith('--key=value') || arg.startsWith('--key=')) {
      const key = arg.slice(2).split('=')[0]
      const value = 'value' in arg ? arg.slice(arg.indexOf('=') + 1) : '='
      result[key] = result[key] || []
      result[key].push(value)
    } else if (result._.length && result._[result._.length - 1] !== 'undefined' ) {
      const last = result._.length - 1
      result[arg.slice(2)] = result._[last]
      result._.splice(last, 1)
    } else result[arg.slice(2)] = true
  }
  return result
}

