export function parseArgs(argv) {
  const result = { _: [] }

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    if (arg === '_' || !arg.startsWith('-')) {
      result._.push(arg)
      continue
    }

    if (arg.startsWith('--') && arg.includes('=')) {
      const [key, value] = arg.substring(2).split('=')
      result[key] = result[key] || []
      if (typeof result[key] === 'boolean') {
        result[key] = value
      } else if (!Array.isArray(result[key])) {
        result[key] = [result[key]]
      }
      result[key].push(value)
      continue
    }

    if (result._.length > 0 && result._[result._.length - 1] !== '---') {
      const value = result._.pop()
      result[arg.substring(2)] = result[arg.substring(2)] || []
      if (typeof result[arg.substring(2)] === 'boolean') {
        result[arg.substring(2)] = value
      } else if (!Array.isArray(result[arg.substring(2)])) {
        result[arg.substring(2)] = [result[arg.substring(2)]]
      }
      result[arg.substring(2)].push(value)
    } else {
      (result[arg.substring(2)] = true)
    }
  }

  return result
}

